import React, { useEffect } from 'react'
import { Button, Card, CardContent, Divider, MenuItem, Stack, TextField } from '@mui/material';
import List from '@mui/material/List'
import ListItem from '@mui/material/ListItem'
import ListItemText from '@mui/material/ListItemText'
import ListItemAvatar from '@mui/material/ListItemAvatar'
import Avatar from '@mui/material/Avatar'
import { PageContainer } from '@/components/PageContainer'
import { StatusMessage } from '@/components/StatusMessage'
import BadgeIcon from '@mui/icons-material/Badge';
import StorefrontIcon from '@mui/icons-material/Storefront';
import { ApiResponse, CallStatus } from '@/types/api.types'
import { StateData } from '@/store';
import { BusinessResult, UpdateBusinessPayload } from '@/types/business.types';
import { BusinessServices, BusinessServicesError } from '@/api';
import { BusinessCategories } from '@/constants/StaticLists';
import { useNavigate } from '@tanstack/react-router';
import { Pathname } from '@/constants/Routes';
import { Link } from '@tanstack/react-router';
import useStore from '@/store';
import { ApiGlobalStateManager } from '@/lib/api-state';
import { submitButtonStyle } from '@/constants/ThemeConstants';

interface BusinessUpdateProps {
    businessId?: string;
}

export const BusinessUpdate: React.FC<BusinessUpdateProps> = ({ businessId }) => {
    const [formData, setFormData] = React.useState<UpdateBusinessPayload>({} as UpdateBusinessPayload);
    const [isFormValid, setIsFormValid] = React.useState<boolean>(false);
    const [isFormTouched, setIsFormTouched] = React.useState<boolean>(false);
    const [isSubmitted, setIsSubmitted] = React.useState<boolean>(false);
    const [businessUpdateResult, setBusinessUpdateResult] = React.useState<StateData<BusinessResult>>({} as StateData<BusinessResult>);
    const { businessStateList, setBusinessStateList } = useStore();
    const navigate = useNavigate();

    useEffect(() => {
        if (!businessId) return;
        const business = Array.isArray(businessStateList.data) ? businessStateList.data.find(b => b.id === businessId) : undefined;
        if (business) {
            setFormData(business);
        }
        else {
            BusinessServices.GetBusinessById(businessId)
                .then(response => {
                    const apiResult = response.data as ApiResponse<BusinessResult>;
                    setFormData(apiResult.result as UpdateBusinessPayload);
                })
                .catch(() => {
                    navigate({ to: Pathname.Business as string });
                });
        }
    }, [businessId]);

    const validateName = (): boolean => {
        return formData && !!formData.name && formData.name.length >= 3;
    }

    const validateCategory = (): boolean => {
        return formData && !!formData.category && formData.category.length >= 3;
    }

    const validateDetails = (): boolean => {
        return formData && !!formData.details && formData.details.length >= 3;
    }

    const validateAddress = (): boolean => {
        return formData && !!formData.address && formData.address.length >= 3;
    }

    const validatePinCode = (): boolean => {
        return formData && !!formData.pinCode && formData.pinCode.toString().length === 6;
    }

    const validatePhone = (): boolean => {
        const indianPhoneRegex = /^[6-9]\d{9}$/;
        return formData && !!formData.phone && indianPhoneRegex.test(formData.phone);
    }

    const validateForm = () => {
        setIsFormValid(
            validateName() &&
            validateCategory() &&
            validateDetails() &&
            validatePhone() &&
            validateAddress() &&
            validatePinCode()
        );
        return isFormValid;
    }

    // Handle Form Submit
    const handleFormSubmit = (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setIsFormTouched(true);
        if (validateForm()) {
            setIsSubmitted(true);
            // Strip empty optional strings so server-side [EmailAddress]/[Url] validators
            // don't reject "" — they only run when a value is supplied.
            const optionalStringFields: Array<keyof UpdateBusinessPayload> = ['category', 'mapLink', 'offer', 'email', 'website'];
            const payload = { ...formData };
            optionalStringFields.forEach(f => {
                if (typeof payload[f] === 'string' && (payload[f] as string).trim() === '') {
                    (payload as any)[f] = undefined;
                }
            });
            ApiGlobalStateManager(BusinessServices.UpdateBusiness(payload), setBusinessUpdateResult).then(() => {
                const updatedBusinessList = businessStateList.data.map(business =>
                    business.id === formData.id ? { ...business, ...formData } : business
                );
                setBusinessStateList({ ...businessStateList, data: updatedBusinessList });
            });            
        }
    }

    return (
        <>
            <PageContainer
                icon={<StorefrontIcon color="primary" />}
                title="Edit business"
                subtitle="Update your business details."
            >
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                {businessUpdateResult.status === CallStatus.Success ? (
                    <Stack direction='column' spacing={2} sx={{ margin: 2, alignItems: 'flex-start' }}>
                        <StatusMessage
                            currentStatus={CallStatus.Success}
                            successMessage="Business updated successfully! 🎉"
                        />
                        <Button 
                            variant="contained" 
                            component={Link} 
                            to={Pathname.Business}
                            sx={{ textTransform: 'none' }}
                        >
                            Go to My Businesses
                        </Button>
                    </Stack>
                ) : (
                    <form onSubmit={handleFormSubmit} onChange={() => { setIsFormTouched(true); validateForm(); }}>
                        <List>
                            <ListItem>
                                <ListItemAvatar>
                                    <Avatar>
                                        <BadgeIcon />
                                    </Avatar>
                                </ListItemAvatar>
                                <ListItemText primary="Update your Business" />
                            </ListItem>
                            <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                <TextField
                                    label="Business Name"
                                    required
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    error={isFormTouched && !validateName()}
                                    value={formData.name || ''}
                                />
                                <TextField
                                    select
                                    label="Category"
                                    required
                                    onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                                    error={isFormTouched && !validateCategory()}
                                    value={formData.category || ''}
                                >
                                    {BusinessCategories.map((category) => (
                                        <MenuItem key={category} value={category}>
                                            {category}
                                        </MenuItem>
                                    ))}
                                </TextField>
                                <TextField
                                    label="Details / Specialisation"
                                    multiline
                                    rows={4}
                                    required
                                    onChange={(e) => setFormData({ ...formData, details: e.target.value })}
                                    error={isFormTouched && !validateDetails()}
                                    value={formData.details || ''}
                                />
                                 <TextField
                                    label="Phone"
                                    required
                                    onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                                    error={isFormTouched && !validatePhone()}
                                    value={formData.phone || ''}
                                />
                                <TextField
                                    label="Address"
                                    required
                                    onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                                    error={isFormTouched && !validateAddress()}
                                    value={formData.address || ''}
                                />
                                <TextField
                                    label="Pin Code"
                                    required
                                    onChange={(e) => setFormData({ ...formData, pinCode: Number(e.target.value) })}
                                    error={isFormTouched && !validatePinCode()}
                                    value={formData.pinCode || ''}
                                />
                                <TextField
                                    label="GoogleMap Link"                                    
                                    onChange={(e) => setFormData({ ...formData, mapLink: e.target.value })}
                                    value={formData.mapLink || ''}
                                />
                                <TextField
                                    label="Offer / Discount"
                                    onChange={(e) => setFormData({ ...formData, offer: e.target.value })}
                                    value={formData.offer || ''}
                                />                               
                                <TextField
                                    label="Email"
                                    type="email"
                                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                    value={formData.email || ''}
                                />
                                <TextField
                                    label="Website"
                                    onChange={(e) => setFormData({ ...formData, website: e.target.value })}
                                    value={formData.website || ''}
                                />
                            </Stack>
                            <Divider />
                            <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                <Button style={submitButtonStyle} disabled={!isFormValid} variant="contained" type="submit">Update</Button>
                                <StatusMessage
                                    currentStatus={businessUpdateResult.status || CallStatus.NotStarted}
                                    failureMessage={BusinessServicesError.UpdateBusinessError(businessUpdateResult.httpStatus)}
                                    notStartedMessage={!isSubmitted ? "Please crosscheck your details before you submit." : undefined}
                                    correlationId={businessUpdateResult.correlationId}
                                />
                            </Stack>
                        </List>
                    </form>
                )}
                    </CardContent>
                </Card>
            </PageContainer>
        </>
    )
}

